//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function (e) {
  let ret = await $c.gus.cfValidate($p, [lc_postSeq]);
  if (!ret) {
    return;
  }
  scwin.tab_Gb = tac_tabControl1.getSelectedTabIndex();
  if (scwin.tab_Gb == "0") {
    // 신청현황(지사별)
    $c.sbm.execute($p, sbm_retrieve);
  } else if (scwin.tab_Gb == "1") {
    //신청현황(Summary)
    $c.sbm.execute($p, sbm_retrieve2);
  } else if (scwin.tab_Gb == "2") {
    //신청현황(SIZE별)
    $c.sbm.execute($p, sbm_retrieve3);
  }
};

